import prometheus_client
from prometheus_client import Summary

# Define a summary metric for HTTP requests with labels for user_id, session_id, and full request path
http_request_summary = Summary(
    'http_requests',
    'HTTP requests',
    ['user_id', 'session_id', 'full_request_path']
)

# Define a function to track HTTP requests with labels for user_id, session_id, and full request path
def track_http_request(user_id, session_id, full_request_path):
    http_request_summary.labels(user_id=user_id, session_id=session_id, full_request_path=full_request_path).observe(1)

# Define a function to create a new metric for each unique user-path combination
def create_metric_for_unique_user_path(user_id, full_request_path):
    # Check if the metric already exists
    if not http_request_summary.labels(user_id=user_id, full_request_path=full_request_path).exists():
        # Create a new metric for the unique user-path combination
        http_request_summary.labels(user_id=user_id, full_request_path=full_request_path).create()